import React from 'react';

interface UserProps {
    imgSrc: string;
    to: string;
}

const User: React.FC<UserProps> = ({ imgSrc, to }) => {
  return (
    <a href={to}>
      <img src={imgSrc} width={34} height={34} alt="icon-user" />
    </a>
  )
}

export default User;
